// n8n Code node: Normalize Input
// Extracts username from URL or @handle; never fabricates profile facts.

const raw =
  $json.body?.instagram_url ||
  $json.body?.instagram_handle ||
  $json.body?.url ||
  $json.instagram_url ||
  $json.instagram_handle ||
  $json.url ||
  '';

if (!raw || String(raw).trim() === '') {
  return [{
    json: {
      ok: false,
      error: 'MISSING_INPUT',
      message: 'Provide instagram_url or instagram_handle in request body.',
    },
  }];
}

let input = String(raw).trim();
input = input.replace(/^@/, '');

let username = input;
const urlMatch = input.match(/instagram\.com\/([A-Za-z0-9._]+)/i);
if (urlMatch) username = urlMatch[1];
username = username.split('?')[0].split('/')[0].replace('@', '').toLowerCase();

if (!/^[a-z0-9._]{1,30}$/i.test(username)) {
  return [{
    json: {
      ok: false,
      error: 'INVALID_HANDLE',
      message: `Could not parse Instagram username from: ${raw}`,
    },
  }];
}

const windowDays = Number($json.body?.window_days || $json.window_days || 30);
const maxPosts = Number($json.body?.max_posts || $json.max_posts || 50);
const enableWhisper = $json.body?.enable_whisper !== false;

return [{
  json: {
    ok: true,
    username,
    profile_url: `https://www.instagram.com/${username}/`,
    window_days: windowDays,
    max_posts: Math.min(Math.max(maxPosts, 10), 100),
    enable_whisper: enableWhisper,
    requested_at: new Date().toISOString(),
    xlsx_api_url: 'https://YOUR-SERVICE-NAME.onrender.com/generate',
  },
}];

// n8n Code node: Compute Analytics + filter window

const ctx = $('Normalize Input').first().json;
const parsed = $('Parse Merged Dataset').first().json;
const profile = parsed.profile;

if (parsed.warning === 'PRIVATE_PROFILE') {
  const ctxPrivate = $('Normalize Input').first().json;
  return [{
    json: {
      ok: true,
      warning: 'PRIVATE_PROFILE',
      message: parsed.message,
      meta: {
        username: profile.username,
        window_days: ctxPrivate.window_days || 30,
        generated_date: new Date().toISOString().slice(0, 10),
      },
      profile,
      posts: [],
      metrics: {
        post_count: 0,
        reel_count: 0,
        total_views: 0,
        total_likes: 0,
        total_engagement: 0,
        avg_views: 0,
        avg_likes: 0,
        avg_engagement_rate: 0,
        avg_views_last_10: 0,
        posting_frequency_per_week: 0,
        low_engagement_reels: 0,
      },
      posting_day_breakdown: [],
      top_posts: [],
      bottom_posts: [],
    },
  }];
}

let posts = [...parsed.posts];

const windowDays = ctx.window_days || 30;
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - windowDays);

posts = posts
  .filter((p) => {
    if (!p.posted_at) return true;
    return new Date(p.posted_at) >= cutoff;
  });

if (!posts.length) {
  return [{
    json: {
      ok: false,
      error: 'NO_POSTS_IN_WINDOW',
      message: `No posts in last ${windowDays} days.`,
      profile,
    },
  }];
}

function engagementRate(p) {
  const views = Number(p.views) || 0;
  if (views <= 0) return 0;
  return (Number(p.engagement) || 0) / views;
}

function statusLabel(p) {
  const views = Number(p.views) || 0;
  const rate = engagementRate(p);
  if (views >= 500000 && rate >= 0.05) return 'Viral';
  if (views >= 100000 && rate >= 0.03) return 'Strong';
  if (views === 0 && (p.likes || 0) > 50000) return 'Top Performer';
  if (rate < 0.01 && views > 0) return 'Needs Work';
  return 'Average';
}

function viewsDisplayRate(rate, views) {
  if (!views) return '0.0%';
  return `${(rate * 100).toFixed(2)}%`;
}

function captionBucket(caption) {
  const words = (caption || '').trim().split(/\s+/).filter(Boolean).length;
  if (words < 30) return 'Short (<30w)';
  if (words < 80) return 'Medium (30-80w)';
  return 'Long (80w+)';
}

function weekdayName(dateStr) {
  const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  return days[new Date(dateStr).getDay()];
}

posts = posts.map((p) => {
  const rate = engagementRate(p);
  return {
    ...p,
    engagement_rate: rate,
    engagement_rate_pct: Math.round(rate * 10000) / 100,
    engagement_rate_display: viewsDisplayRate(rate, p.views),
    status: statusLabel(p),
    topic: p.topic || '',
    hook_type: p.hook_type || '',
    caption_length_bucket: captionBucket(p.caption),
    weekday: p.posted_at ? weekdayName(p.posted_at) : 'Unknown',
  };
});

const totalViews = posts.reduce((s, p) => s + (Number(p.views) || 0), 0);
const totalLikes = posts.reduce((s, p) => s + (Number(p.likes) || 0), 0);
const totalEngagement = posts.reduce((s, p) => s + (Number(p.engagement) || 0), 0);
const postsWithViews = posts.filter((p) => (p.views || 0) > 0);
const avgViews = postsWithViews.length ? totalViews / postsWithViews.length : 0;
const avgLikes = totalLikes / posts.length;
const avgEngagementRate = totalViews > 0 ? totalEngagement / totalViews : 0;

// Chronological last 10 posts (not top-by-views)
const chronoDesc = [...posts].sort((a, b) => {
  const da = a.posted_at ? new Date(a.posted_at).getTime() : 0;
  const db = b.posted_at ? new Date(b.posted_at).getTime() : 0;
  return db - da;
});
const last10Chrono = chronoDesc.slice(0, 10);
const avgViewsLast10 =
  last10Chrono.reduce((s, p) => s + (Number(p.views) || 0), 0) / Math.max(last10Chrono.length, 1);

const reelsOnly = posts.filter((p) => p.type === 'Reel');
const postingFrequencyPerWeek = (posts.length / windowDays) * 7;

const dayMap = {};
for (const p of posts) {
  const d = p.weekday || 'Unknown';
  if (!dayMap[d]) dayMap[d] = { count: 0, views: [], rates: [] };
  dayMap[d].count += 1;
  dayMap[d].views.push(Number(p.views) || 0);
  dayMap[d].rates.push(p.engagement_rate || 0);
}

const postingDayBreakdown = Object.entries(dayMap)
  .map(([day, v]) => {
    const avgV = v.views.reduce((a, b) => a + b, 0) / v.views.length;
    const avgR = v.rates.reduce((a, b) => a + b, 0) / v.rates.length;
    return {
      day,
      count: v.count,
      avg_views: avgV,
      avg_views_display: Math.round(avgV).toLocaleString('en-US'),
      avg_eng_rate_display: `${(avgR * 100).toFixed(2)}%`,
    };
  })
  .sort((a, b) => b.avg_views - a.avg_views);

const sortedByViews = [...posts].sort((a, b) => (b.views || 0) - (a.views || 0));
const topPosts = sortedByViews.slice(0, 5);
const bottomPosts = [...posts]
  .sort((a, b) => {
    const av = a.views || 0;
    const bv = b.views || 0;
    if (av === bv) return (a.engagement_rate || 0) - (b.engagement_rate || 0);
    return av - bv;
  })
  .slice(0, 5);

const lowEngReels = posts.filter(
  (p) => p.type === 'Reel' && (p.engagement_rate || 0) < 0.01
).length;

// Default list order: by views desc for audit table
posts.sort((a, b) => (b.views || 0) - (a.views || 0));

return [{
  json: {
    ok: true,
    meta: {
      username: profile.username,
      window_days: windowDays,
      generated_date: new Date().toISOString().slice(0, 10),
    },
    profile,
    posts,
    metrics: {
      post_count: posts.length,
      reel_count: reelsOnly.length,
      total_views: totalViews,
      total_likes: totalLikes,
      total_engagement: totalEngagement,
      avg_views: Math.round(avgViews),
      avg_likes: Math.round(avgLikes),
      avg_engagement_rate: avgEngagementRate,
      avg_views_last_10: Math.round(avgViewsLast10),
      posting_frequency_per_week: Math.round(postingFrequencyPerWeek * 10) / 10,
      low_engagement_reels: lowEngReels,
    },
    posting_day_breakdown: postingDayBreakdown,
    top_posts: topPosts,
    bottom_posts: bottomPosts,
  },
}];

// n8n Code node: Build OpenAI classification request (structured JSON only)

const data = $('Compute Analytics').first().json;
const posts = data.posts.slice(0, 30);

const promptPosts = posts.map((p, idx) => ({
  index: idx,
  url: p.url,
  type: p.type,
  caption_preview: (p.caption || '').slice(0, 500),
  views: p.views,
  likes: p.likes,
}));

const systemPrompt = `You are an Instagram content analyst. Classify ONLY from provided captions and metrics.
Return strict JSON: {"posts":[{"index":0,"topic":"...","hook_type":"..."}],"primary_language":"..."}
topic must be one of: General, Education, Entertainment, Product, Lifestyle, Sports, News, Other
hook_type must be one of: Educational, Question, Story, CTA, Trend, Emotional, Other
Never invent metrics. If unclear, use General and Other.\nAlso return primary_language (string, e.g. English, Hindi) inferred only from bio/captions, or empty string if unknown.`;

const userPrompt = JSON.stringify({
  username: data.meta.username,
  posts: promptPosts,
});

return [{
  json: {
    openai_body: {
      model: 'openai/gpt-4o-mini',
      temperature: 0.2,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt },
      ],
    },
    analytics: data,
  },
}];

// n8n Code node: Merge OpenAI classifications into posts

const analytics = $('Build AI Request').first().json.analytics;
let posts = [...analytics.posts];

const aiRaw =
  $json.choices?.[0]?.message?.content ||
  $json.message?.content ||
  $json.content ||
  '{}';

let parsed = {};
let primaryLanguage = '';
try {
  parsed = JSON.parse(aiRaw);
  primaryLanguage = parsed.primary_language || '';
} catch (e) {
  parsed = { posts: [] };
}

const byIndex = {};
for (const row of parsed.posts || []) {
  if (row.index != null) byIndex[row.index] = row;
}

posts = posts.map((p, idx) => ({
  ...p,
  topic: byIndex[idx]?.topic || p.topic || 'General',
  hook_type: byIndex[idx]?.hook_type || p.hook_type || 'Other',
}));

const topicStats = aggregate(posts, 'topic');
const hookStats = aggregate(posts.filter((p) => p.type === 'Reel'), 'hook_type');
const captionStats = aggregate(posts, 'caption_length_bucket');
const dayStats = analytics.posting_day_breakdown || [];

const bestTopic = topicStats[0]?.key || 'General';
const bestHook = hookStats[0]?.key || 'Other';
const bestDay = dayStats[0]?.day || 'Unknown';
const worstDay = dayStats[dayStats.length - 1]?.day || 'Unknown';
const bestCaption = captionStats[0]?.key || 'Short (<30w)';

const insights = buildInsights({
  analytics: { ...analytics, posts },
  bestTopic,
  bestHook,
  bestDay,
  worstDay,
  bestCaption,
  topicStats,
  hookStats,
  captionStats,
});

return [{
  json: {
    ok: true,
    ...analytics,
    posts,
    insights,
    primary_language: primaryLanguage,
  },
}];

function aggregate(posts, field) {
  const m = {};
  for (const p of posts) {
    const k = p[field] || 'Unknown';
    if (!m[k]) m[k] = { views: [], rates: [] };
    m[k].views.push(Number(p.views) || 0);
    m[k].rates.push(Number(p.engagement_rate) || 0);
  }
  return Object.entries(m)
    .map(([key, v]) => {
      const avgViews = v.views.reduce((a, b) => a + b, 0) / v.views.length;
      const avgRate = v.rates.reduce((a, b) => a + b, 0) / v.rates.length;
      return { key, avgViews, avgRate, count: v.views.length };
    })
    .sort((a, b) => b.avgViews - a.avgViews);
}

function buildInsights(ctx) {
  const m = ctx.analytics.metrics;
  const top = ctx.analytics.top_posts[0];
  return {
    sections: [
      [
        '  WHAT IS WORKING',
        [
          ['BEST TOPIC', ctx.bestTopic, 'BEST POSTING DAY', ctx.bestDay],
          [
            `Avg ${Math.round(ctx.topicStats[0]?.avgViews || 0).toLocaleString()} views — focus here for max reach`,
            '',
            `Avg ${Math.round((ctx.analytics.posting_day_breakdown[0]?.avg_views) || 0).toLocaleString()} views — post more on this day`,
            '',
          ],
          ['BEST HOOK TYPE', ctx.bestHook, 'BEST CAPTION LENGTH', ctx.bestCaption],
          [
            `Avg ${Math.round(ctx.hookStats[0]?.avgViews || 0).toLocaleString()} views — use this opening style more`,
            '',
            `Avg ${Math.round(ctx.captionStats[0]?.avgViews || 0).toLocaleString()} views — match this length going forward`,
            '',
          ],
          [
            'AVG ENGAGEMENT RATE',
            `${(m.avg_engagement_rate * 100).toFixed(2)}%`,
            'TOP REEL HOOK',
            (top?.caption_preview || '').slice(0, 60),
          ],
        ],
      ],
      [
        '  WHAT NEEDS IMPROVEMENT',
        [
          [
            'POSTING FREQUENCY',
            `${m.posting_frequency_per_week}/week  —  On track`,
            'LOW ENGAGEMENT REELS',
            `${m.low_engagement_reels} reels below 1%`,
          ],
          [
            `${m.post_count} reels in ${ctx.analytics.meta.window_days} days. Target 4-5/week for consistent algorithm reach.`,
            '',
            'These reels lack clear CTAs. End with: "Comment [word] if you want [result]"',
            '',
          ],
          ['WEAKEST HOOK TYPE', ctx.hookStats[ctx.hookStats.length - 1]?.key || 'Other', 'WORST POSTING DAY', ctx.worstDay],
        ],
      ],
      [
        '  ACTION PLAN  —  NEXT 30 DAYS',
        [
          ['1.  DOUBLE DOWN ON ' + ctx.bestTopic.toUpperCase(), '', '2.  USE MORE ' + ctx.bestHook.toUpperCase() + ' HOOKS', ''],
          [
            `60% of next month content → ${ctx.bestTopic}.`,
            '',
            `This hook style averages ${Math.round(ctx.hookStats[0]?.avgViews || 0).toLocaleString()} views.`,
            '',
          ],
          ['3.  POST ON ' + ctx.bestDay.toUpperCase(), '', '4.  REPURPOSE TOP REEL', ''],
          [
            `Best day = ${ctx.bestDay}. Avoid ${ctx.worstDay} if possible.`,
            '',
            top ? `Your #1 post got ${(top.views || 0).toLocaleString()} views.` : '',
            '',
          ],
        ],
      ],
    ],
    posting_day_breakdown: ctx.analytics.posting_day_breakdown,
  };
}

const ctx = $('Normalize Input').first().json;
const merged = $('Merge AI Classifications').first().json;
const enable = ctx.enable_whisper !== false;
const reels = (merged.posts || [])
  .filter((p) => p.type === 'Reel' && p.video_url)
  .slice(0, 7);

if (!enable || !reels.length) {
  return [{ json: { skip: true, skip_all: true } }];
}

return reels.map((p) => ({
  json: {
    skip: false,
    skip_all: false,
    url: p.url,
    video_url: p.video_url,
    caption: p.caption,
    posted_at: p.posted_at,
    views: p.views,
  },
}));

const merged = $('Merge AI Classifications').first().json;
const reelPosts = (merged.posts || []).filter((p) => p.type === 'Reel');

const whisperByUrl = {};
try {
  const whisperRows = $('Map Whisper Row').all();
  for (const row of whisperRows) {
    const j = row.json;
    if (j.url && j.text) {
      whisperByUrl[j.url] = { url: j.url, source: j.source || 'Whisper', text: j.text };
    }
  }
} catch (e) {
  // Whisper branch not executed
}

return reelPosts.map((p) => ({
  json: whisperByUrl[p.url] || {
    url: p.url,
    source: 'Caption',
    text: p.caption || '',
    posted_at: p.posted_at,
    views: p.views,
  },
}));

// n8n Code node: Build final JSON payload for XLSX API + webhook response

const merged = $('Merge AI Classifications').first().json;
const profile = merged.profile;
const posts = merged.posts;
const metrics = merged.metrics;
const meta = merged.meta;
const privateWarning = merged.warning === 'PRIVATE_PROFILE' ? merged.message : '';

// Transcripts from Whisper branch items (if any) merged via $('Merge Transcripts')
let transcriptItems = [];
try {
  transcriptItems = $('Merge Transcripts').all().map((i) => i.json);
} catch (e) {
  transcriptItems = [];
}

const transcriptByUrl = {};
for (const t of transcriptItems) {
  if (t.url) transcriptByUrl[t.url] = t;
}

const reelPosts = posts.filter((p) => p.type === 'Reel');

const transcripts = reelPosts.map((p, idx) => {
  const hit = transcriptByUrl[p.url];
  const source = hit?.source || (p.is_video ? 'Caption' : 'Caption');
  const text = hit?.text || p.caption || '';
  return {
    index: idx + 1,
    date: p.posted_at,
    url: p.url,
    views: p.views,
    source,
    text,
  };
});

const whisperCount = transcripts.filter((t) => t.source === 'Whisper').length;
const captionCount = transcripts.length - whisperCount;

const influencerRow = {
  'Full Name': profile.full_name || '',
  'Channel Name': profile.username || '',
  'Influencer Category': profile.business_category || '',
  'Gender': '',
  'Email Id': '',
  'CONTACT No.': '',
  'Instagram Link': profile.profile_url || '',
  'IG Followers': profile.followers ?? '',
  'You Tube Link': '',
  'YT Subs': '',
  'Facebook Link': '',
  'FB Followers': '',
  'Linkedin Link': '',
  'Linkedin Followers': '',
  'Snapchat Link': '',
  'SC Followers': '',
  'External Link': profile.external_url || '',
  'Country': '',
  'State': '',
  'City': '',
  'Region': '',
  'Regional/Primary Language': merged.primary_language || '',
  'Influencer Type': profile.is_verified ? 'Verified' : 'Creator',
  'Primary Platform': 'Instagram',
  'AVG Views (Last 10 Posts)': metrics.avg_views_last_10 ?? '',
};

const auditPosts = posts.map((p) => ({
  date: p.posted_at,
  type: p.type,
  url: p.url,
  views: p.views,
  likes: p.likes,
  comments: p.comments,
  engagement: p.engagement,
  engagement_rate_pct: p.engagement_rate_pct,
  engagement_rate_display: p.engagement_rate_display,
  status: p.status,
  topic: p.topic,
  hook_type: p.hook_type,
  caption_preview: p.caption_preview,
}));

return [{
  json: {
    ok: true,
    influencer_profile_row: influencerRow,
    audit: {
      meta,
      metrics: {
        post_count: metrics.post_count,
        total_views: metrics.total_views,
        avg_views: metrics.avg_views,
        avg_likes: metrics.avg_likes,
        avg_engagement_rate: metrics.avg_engagement_rate,
      },
      posts: auditPosts,
      top_posts: merged.top_posts,
      bottom_posts: merged.bottom_posts,
      insights: merged.insights,
      transcripts,
      transcript_summary: `  Transcription summary: ${whisperCount} reels transcribed via Whisper  ·  ${captionCount} reels using caption fallback`,
    },
    field_availability: {
      scraped: [
        'username',
        'full_name',
        'followers',
        'biography',
        'external_url',
        'post_urls',
        'likes',
        'comments',
        'views_on_video',
        'captions',
        'timestamps',
      ],
      calculated: [
        'engagement',
        'engagement_rate',
        'avg_views',
        'posting_frequency',
        'posting_day_breakdown',
        'top_bottom_posts',
      ],
      ai_inferred: ['topic', 'hook_type', 'recommendations', 'insights_text'],
      unavailable_left_blank: [
        'gender',
        'email',
        'phone',
        'youtube',
        'facebook',
        'linkedin',
        'snapchat',
        'country',
        'state',
        'city',
        'language_unless_inferred',
      ],
    },
  },
}];

const payload = $('Build Workbook Payload').first().json;
const gen = $json;
const infB64 = gen.influencer_xlsx_base64;
const audB64 = gen.audit_xlsx_base64;
const username = payload.audit?.meta?.username || 'profile';

if (!infB64 || !audB64) {
  return [{
    json: {
      ok: true,
      warning: 'XLSX_API_UNAVAILABLE',
      has_binaries: false,
      data: payload,
      message: 'Workbook API did not return files. Deploy xlsx-api on Render and set xlsx_api_url in Normalize Input.',
    },
  }];
}

return [{
  json: {
    ok: true,
    has_binaries: true,
    username,
    metrics: payload.audit.metrics,
    influencer_filename: gen.influencer_filename,
    audit_filename: gen.audit_filename,
    zip_filename: `${username}_insta_audit_bundle.zip`,
    field_availability: payload.field_availability,
  },
  binary: {
    influencer_xlsx: {
      data: infB64,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: gen.influencer_filename,
    },
    audit_xlsx: {
      data: audB64,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: gen.audit_filename,
    },
  },
}];

