const ctx = $('Normalize Input').first().json;
const run = $json.data || $json;
const datasetId = run.defaultDatasetId || run.defaultDataset?.id;

if (!datasetId) {
  return [{
    json: {
      ok: false,
      error: 'APIFY_RUN_FAILED',
      message: 'Profile Apify run failed — no dataset ID.',
      scrape_kind: 'profile',
      raw: run,
    },
  }];
}

return [{ json: { ...ctx, datasetId, scrape_kind: 'profile' } }];

const rows = $input.all();

if (!rows.length) {
  return [{
    json: {
      ok: false,
      error: 'EMPTY_DATASET',
      message: 'Apify dataset returned zero items.'
    }
  }];
}

return rows.map(row => ({
  json: row.json
}));

const ctx = $('Normalize Input').first().json;
const run = $json.data || $json;
const datasetId = run.defaultDatasetId || run.defaultDataset?.id;

if (!datasetId) {
  return [{
    json: {
      ok: false,
      error: 'APIFY_RUN_FAILED',
      message: 'Posts Apify run failed — no dataset ID.',
      scrape_kind: 'posts',
      raw: run,
    },
  }];
}

return [{ json: { ...ctx, datasetId, scrape_kind: 'posts' } }];

const rows = $input.all();

if (!rows.length) {
  return [{
    json: {
      ok: false,
      error: 'EMPTY_DATASET',
      message: 'Apify dataset returned zero items.'
    }
  }];
}

return rows.map(row => ({
  json: row.json
}));

// Parse AFTER both Profile To Items + Posts To Items ran (posts branch is last in chain).
// Profile: alwaysprimedev/instagram-profile-scraper (followersCount, followsCount, postsCount)
// Posts: apify/instagram-scraper resultsType posts

const ctx = $('Normalize Input').first().json;

let profileItems = [];
let postItems = [];

try {
  profileItems = $('Profile To Items').all().map((i) => i.json);
} catch (e) {
  profileItems = [];
}

try {
  postItems = $('Posts To Items').all().map((i) => i.json);
} catch (e) {
  // Fallback: single-branch workflow
  postItems = $input.all().map((i) => i.json);
}

function mapPostType(raw) {
  const t = String(raw || '').toLowerCase();
  if (t.includes('video') || t === 'reel' || t === 'clips') return 'Reel';
  if (t.includes('side') || t.includes('carousel')) return 'Carousel';
  if (t.includes('image') || t === 'photo') return 'Photo';
  return raw || 'Post';
}

function normalizePost(p) {
  const shortcode = p.shortCode || p.shortcode || p.id || '';
  const url =
    p.url ||
    p.postUrl ||
    (shortcode ? `https://www.instagram.com/p/${shortcode}/` : '');
  const likes = Number(p.likesCount ?? p.likes ?? 0) || 0;
  const comments = Number(p.commentsCount ?? p.comments ?? 0) || 0;
  const views =
    Number(p.videoViewCount ?? p.viewCount ?? p.views ?? p.playCount ?? 0) || 0;
  const ts = p.timestamp || p.takenAt || p.createdAt || p.date;
  const posted_at = ts ? new Date(ts).toISOString().slice(0, 10) : '';
  const caption = (p.caption || p.text || '').trim();
  const isVideo = !!(
    p.isVideo ||
    p.videoUrl ||
    p.video_url ||
    p.type === 'Video' ||
    mapPostType(p.type || p.productType) === 'Reel'
  );
  return {
    id: p.id || shortcode || url,
    shortcode,
    url,
    posted_at,
    type: mapPostType(p.type || (isVideo ? 'Reel' : 'Photo')),
    likes,
    comments,
    views,
    engagement: likes + comments,
    caption,
    caption_preview: caption.slice(0, 120),
    video_url: p.videoUrl || p.video_url || '',
    hashtags: p.hashtags || [],
    is_video: isVideo,
    location: (p.location && (p.location.name || p.location)) || '',
  };
}

function pickCount(row, keys) {
  for (const key of keys) {
    const parts = key.split('.');
    let v = row;
    for (const part of parts) {
      v = v?.[part];
    }
    if (v !== undefined && v !== null && v !== '') {
      const n = Number(v);
      if (!Number.isNaN(n)) return n;
    }
  }
  return null;
}

function buildProfileFromRow(p) {
  if (!p) return null;
  return {
    username: p.username || ctx.username,
    full_name: p.fullName || p.full_name || p.name || '',
    biography: p.biography || p.bio || '',
    followers: pickCount(p, [
      'followersCount',
      'followers',
      'followers_count',
      'followerCount',
      'edge_followed_by.count',
    ]),
    following: pickCount(p, [
      'followsCount',
      'followingCount',
      'follows',
      'following_count',
      'following',
      'edge_follow.count',
      'counts.following',
    ]),
    posts_count: pickCount(p, [
      'postsCount',
      'posts',
      'posts_count',
      'postCount',
      'mediaCount',
      'edge_owner_to_timeline_media.count',
    ]),
    is_verified: !!(p.verified ?? p.isVerified),
    is_private: !!(p.private ?? p.isPrivate),
    external_url: p.externalUrl || p.external_url || '',
    business_category:
      p.businessCategoryName || p.business_category || p.category || '',
    profile_pic_url: p.profilePicUrl || p.profilePicUrlHD || p.profile_pic_url || '',
    profile_url: p.url || p.profileUrl || ctx.profile_url,
    scraped_at: p.scrapedAt || p.extractedAt || new Date().toISOString(),
  };
}

// Profile scraper: first row is usually the account
const profileRow =
  profileItems.find((r) => r.followersCount != null || r.followers != null) ||
  profileItems[0];

let profile = buildProfileFromRow(profileRow);

// Posts: from posts scraper OR latestPosts on profile row
let posts = postItems
  .filter((r) => r.type !== 'profile')
  .filter((r) => !!(r.shortcode || r.shortCode || r.url || r.postUrl || r.caption || r.likesCount))
  .map(normalizePost)
  .filter((p) => p.url);

if (!posts.length && profileRow?.latestPosts?.length) {
  posts = profileRow.latestPosts.map(normalizePost).filter((p) => p.url);
}

if (!profile) {
  return [{
    json: {
      ok: false,
      error: 'NO_PROFILE',
      message: 'Profile scraper returned no profile row. Check Apify Profile Run.',
      username: ctx.username,
    },
  }];
}

if (profile.is_private) {
  return [{
    json: {
      ok: true,
      warning: 'PRIVATE_PROFILE',
      message: 'Profile is private — post metrics unavailable; profile fields only.',
      profile,
      posts: [],
    },
  }];
}

if (!posts.length) {
  return [{
    json: {
      ok: false,
      error: 'NO_POSTS',
      message: 'Posts scraper returned no posts. Check Apify Posts Run.',
      profile,
    },
  }];
}

return [{
  json: {
    ok: true,
    profile,
    posts,
    scrape_meta: {
      profile_item_count: profileItems.length,
      post_item_count: postItems.length,
      posts_from_latestPosts: !postItems.length && !!profileRow?.latestPosts?.length,
    },
  },
}];

const prev = $('Download Reel Video').item.json;
const text = $json.text || $json.transcript || '';
return [{
  json: {
    url: prev.url,
    source: text ? 'Whisper' : 'Caption',
    text: text || prev.caption || '',
    posted_at: prev.posted_at,
    views: prev.views,
  },
}];
